import{a as e,c as t,i as n,n as r,o as i,r as a,s as o,t as s}from"./app-X_Kuuhdi.js";var c=JSON.parse(`{"path":"/humanities/baroque-music.html","title":"바로크 음악 (Baroque Music)","lang":"ko-KR","frontmatter":{"description":"바로크 음악 (Baroque Music) 바로크(Baroque) 음악은 대략 1600년부터 1750년까지의 서양 예술 음악을 가리킨다. 르네상스(Renaissance) 음악에서 이어지고, 이후 고전주의(Classical) 시대로 넘어가는 음악 역사의 핵심 시기다. J.S. 바흐가 1750년 사망하면서 바로크 시대의 ...","permalink":"/humanities/baroque-music","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"바로크 음악 (Baroque Music)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T20:48:55.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/humanities/baroque-music"}],["meta",{"property":"og:title","content":"바로크 음악 (Baroque Music)"}],["meta",{"property":"og:description","content":"바로크 음악 (Baroque Music) 바로크(Baroque) 음악은 대략 1600년부터 1750년까지의 서양 예술 음악을 가리킨다. 르네상스(Renaissance) 음악에서 이어지고, 이후 고전주의(Classical) 시대로 넘어가는 음악 역사의 핵심 시기다. J.S. 바흐가 1750년 사망하면서 바로크 시대의 ..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T20:48:55.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T20:48:55.000Z"}]]},"git":{"createdTime":1781277665000,"updatedTime":1781297335000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":2,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"47b5aed4ca177bf4af7be2a57306ea9a97ab434f","time":1781297335000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"0613_final"},{"hash":"8227255e0018b0d2c63e50076b5cc2406a472c1d","time":1781277665000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"feat: add SEO plugins, new articles (Baroque/FC/fidget), sidebar updates","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"humanities/baroque-music.md","autoDesc":true}`),l={name:`baroque-music.md`},u={class:`print-section`};function d(s,c,l,d,f,p){let m=t(`DateMeta`);return o(),a(`div`,null,[r(`section`,u,[c[0]||=r(`h1`,{id:`바로크-음악-baroque-music`,tabindex:`-1`},[r(`a`,{class:`header-anchor`,href:`#바로크-음악-baroque-music`},[r(`span`,null,`바로크 음악 (Baroque Music)`)])],-1),i(m),c[1]||=r(`p`,null,`바로크(Baroque) 음악은 대략 1600년부터 1750년까지의 서양 예술 음악을 가리킨다. 르네상스(Renaissance) 음악에서 이어지고, 이후 고전주의(Classical) 시대로 넘어가는 음악 역사의 핵심 시기다. J.S. 바흐가 1750년 사망하면서 바로크 시대의 종언을 상징적으로 표시한다.`,-1),c[2]||=r(`p`,null,[e(`"바로크(Baroque)"는 원래 포르투갈어 `),r(`strong`,null,`barroco`),e(`, 즉 "불규칙하게 생긴 진주"를 뜻하는 단어에서 유래했다. 당시 이 시대 예술에 대한 부정적 평가(복잡하고 과도하다는 의미)로 쓰이던 단어였으나, 이후 이 시대 예술 전체를 가리키는 중립적 명칭으로 정착했다.`)],-1)]),c[3]||=n(`<section class="print-section"><h2 id="바로크-음악의-핵심-특징" tabindex="-1"><a class="header-anchor" href="#바로크-음악의-핵심-특징"><span>바로크 음악의 핵심 특징</span></a></h2></section><section class="print-section"><h3 id="통주저음-basso-continuo" tabindex="-1"><a class="header-anchor" href="#통주저음-basso-continuo"><span>통주저음 (Basso Continuo)</span></a></h3><p>바로크 음악의 가장 큰 특징. 저음 악기(첼로, 비올로네, 바순 등)가 화음의 기초 베이스라인을 지속적으로 연주하고, 건반 악기(하프시코드, 오르간)가 그 위에 즉흥적으로 화음을 채워 넣는다. 이 베이스-화성의 틀이 악곡 전체를 지탱한다.</p><p>통주저음은 일종의 <strong>화성의 뼈대</strong>로, 모든 바로크 앙상블에서 항상 존재했다. 고전주의 시대에 접어들며 사라진 이 기법은 바로크 음악과 고전음악을 구분하는 핵심 차이 중 하나다.</p></section><section class="print-section"><h3 id="대위법-counterpoint" tabindex="-1"><a class="header-anchor" href="#대위법-counterpoint"><span>대위법 (Counterpoint)</span></a></h3><p>여러 개의 독립적인 선율(성부)이 서로 어우러져 화성을 형성하는 기법. J.S. 바흐는 대위법의 최고 정점으로 꼽히며, 그의 <strong>푸가</strong>(Fugue)는 대위법의 완성형이다.</p><p>푸가는 하나의 주제(subject)를 여러 성부가 돌아가며 모방·발전시키는 형식이다. 바흐의 평균율 클라비어 곡집 24쌍의 프렐류드와 푸가는 모든 장·단조를 한 쌍씩 다룬다.</p></section><section class="print-section"><h3 id="장식음-ornamentation" tabindex="-1"><a class="header-anchor" href="#장식음-ornamentation"><span>장식음 (Ornamentation)</span></a></h3><p>바로크 악보에는 <strong>트릴(trill), 모르덴트(mordent), 아포지아투라(appoggiatura)</strong> 등의 장식음 기호가 가득하다. 연주자는 이 기호들을 시대 관습에 따라 해석해 즉흥적으로 구현해야 했다. 현대 편집 악보와 다른 해석이 많아, &quot;역사적 연주법(HIP, Historically Informed Performance)&quot;이 바로크 음악 해석의 중심 과제다.</p></section><section class="print-section"><h3 id="감정-표현의-이론화-정서론-affektenlehre" tabindex="-1"><a class="header-anchor" href="#감정-표현의-이론화-정서론-affektenlehre"><span>감정 표현의 이론화: 정서론 (Affektenlehre)</span></a></h3><p>바로크 시대에는 음악이 특정 감정(분노, 슬픔, 기쁨 등)을 표현하고 청자에게 전달해야 한다는 이론이 발전했다. 이를 <strong>정서론</strong>(Theory of Affections)이라 한다. 특정 조성, 리듬 패턴, 음정이 특정 감정에 대응한다고 보았으며, 작곡가는 이 원칙에 따라 음악을 구성했다.</p></section><section class="print-section"><h2 id="주요-작곡가" tabindex="-1"><a class="header-anchor" href="#주요-작곡가"><span>주요 작곡가</span></a></h2></section><section class="print-section"><h3 id="요한-제바스티안-바흐-johann-sebastian-bach-1685–1750" tabindex="-1"><a class="header-anchor" href="#요한-제바스티안-바흐-johann-sebastian-bach-1685–1750"><span>요한 제바스티안 바흐 (Johann Sebastian Bach, 1685–1750)</span></a></h3><p>바로크 음악의 정점이자 서양 음악사 최고의 작곡가 중 한 명. 독일 아이제나흐 출생. 라이프치히 성 토마스 교회(Thomaskirche)의 칸토르(Cantor)로 근무하며 방대한 교회 음악과 기악 작품을 남겼다.</p><p><strong>주요 작품</strong></p><table><thead><tr><th>장르</th><th>작품</th></tr></thead><tbody><tr><td>오르간</td><td>토카타와 푸가 d단조(BWV 565)</td></tr><tr><td>건반</td><td>평균율 클라비어 곡집 1·2권, 골드베르크 변주곡(BWV 988)</td></tr><tr><td>오케스트라</td><td>브란덴부르크 협주곡(BWV 1046–1051) 6곡</td></tr><tr><td>무반주</td><td>무반주 바이올린 파르티타·소나타(BWV 1001–1006)</td></tr><tr><td>교회 칸타타</td><td>약 200곡 (Cantata BWV 82 &quot;Ich habe genug&quot; 등)</td></tr><tr><td>오라토리오</td><td>마태 수난곡(BWV 244), b단조 미사(BWV 232)</td></tr></tbody></table><p>바흐는 당대보다 사후에 재평가받았다. 1829년 펠릭스 멘델스존이 마태 수난곡을 100년 만에 부활 공연하면서 바흐의 대중적 재발견이 시작됐다.</p></section><section class="print-section"><h3 id="게오르크-프리드리히-헨델-george-frideric-handel-1685–1759" tabindex="-1"><a class="header-anchor" href="#게오르크-프리드리히-헨델-george-frideric-handel-1685–1759"><span>게오르크 프리드리히 헨델 (George Frideric Handel, 1685–1759)</span></a></h3><p>바흐와 같은 해 태어난 독일 출신 작곡가. 이탈리아에서 오페라를 익히고 영국에 정착해 영국 음악계를 이끌었다.</p><table><thead><tr><th>작품</th><th>내용</th></tr></thead><tbody><tr><td>메시아(Messiah, 1741)</td><td>오라토리오. 할렐루야 합창 등 포함. 초연 당시 국왕이 기립했다는 일화로 유명</td></tr><tr><td>수상 음악(Water Music)</td><td>왕실 수상 퍼레이드를 위한 관현악 모음곡</td></tr><tr><td>왕궁의 불꽃놀이 음악</td><td>1749년 런던 불꽃놀이 행사 위촉곡</td></tr></tbody></table></section><section class="print-section"><h3 id="안토니오-비발디-antonio-vivaldi-1678–1741" tabindex="-1"><a class="header-anchor" href="#안토니오-비발디-antonio-vivaldi-1678–1741"><span>안토니오 비발디 (Antonio Vivaldi, 1678–1741)</span></a></h3><p>이탈리아 베네치아 출신. 협주곡(Concerto) 형식의 확립에 결정적인 역할을 했으며, 독주 악기 + 오케스트라의 대화 구조를 체계화했다.</p><table><thead><tr><th>작품</th><th>내용</th></tr></thead><tbody><tr><td>사계(Le quattro stagioni)</td><td>바이올린 협주곡 Op.8 중 1~4번. 각 계절을 음악으로 묘사한 표제음악</td></tr><tr><td>L&#39;estro armonico (Op.3)</td><td>12개 협주곡 모음. J.S. 바흐가 건반 편곡을 남길 만큼 당시 유럽 전역에 영향을 미침</td></tr></tbody></table><p>비발디는 베네치아 고아원 오스페달레 델라 피에타(Ospedale della Pietà)의 음악 교사로 일하며 소녀들을 위한 방대한 협주곡을 작성했다.</p></section><section class="print-section"><h3 id="클라우디오-몬테베르디-claudio-monteverdi-1567–1643" tabindex="-1"><a class="header-anchor" href="#클라우디오-몬테베르디-claudio-monteverdi-1567–1643"><span>클라우디오 몬테베르디 (Claudio Monteverdi, 1567–1643)</span></a></h3><p>르네상스에서 바로크로의 전환을 이끈 선구자. <strong>최초의 오페라</strong>로 간주되는 《오르페오(L&#39;Orfeo, 1607)》를 작곡했다. 독창적인 불협화음 처리법과 극적 표현으로 바로크 음악의 기초를 닦았다.</p></section><section class="print-section"><h3 id="헨리-퍼셀-henry-purcell-1659–1695" tabindex="-1"><a class="header-anchor" href="#헨리-퍼셀-henry-purcell-1659–1695"><span>헨리 퍼셀 (Henry Purcell, 1659–1695)</span></a></h3><p>영국 바로크의 대표 작곡가. 오페라 《디도와 에네아스(Dido and Aeneas, 1689)》의 〈디도의 탄식(Dido&#39;s Lament)〉은 비통한 그라운드 베이스(ground bass) 기법으로 유명하다.</p></section><section class="print-section"><h2 id="주요-음악-형식" tabindex="-1"><a class="header-anchor" href="#주요-음악-형식"><span>주요 음악 형식</span></a></h2><table><thead><tr><th>형식</th><th>설명</th></tr></thead><tbody><tr><td><strong>푸가 (Fugue)</strong></td><td>하나의 주제를 여러 성부가 모방·발전. 대위법의 정수</td></tr><tr><td><strong>협주곡 (Concerto)</strong></td><td>독주 악기 vs 오케스트라의 대화. 비발디, 바흐가 발전</td></tr><tr><td><strong>콘체르토 그로소 (Concerto Grosso)</strong></td><td>소규모 독주군(concertino) vs 전체 합주(ripieno)</td></tr><tr><td><strong>소나타 (Sonata)</strong></td><td>실내악·독주용. 교회 소나타(da chiesa)와 실내 소나타(da camera) 구분</td></tr><tr><td><strong>오페라 (Opera)</strong></td><td>바로크 초기에 탄생. 몬테베르디의 오르페오가 효시</td></tr><tr><td><strong>오라토리오 (Oratorio)</strong></td><td>종교적 내용의 대규모 성악 작품. 무대 장치 없음</td></tr><tr><td><strong>칸타타 (Cantata)</strong></td><td>독창·합창·기악 앙상블. 바흐의 교회 칸타타가 대표</td></tr><tr><td><strong>샤콘느·파사칼리아 (Chaconne/Passacaglia)</strong></td><td>반복 베이스 위에 변주. 바흐 무반주 파르티타 2번 d단조의 샤콘느가 유명</td></tr><tr><td><strong>프렐류드 (Prelude)</strong></td><td>즉흥적 성격의 서주곡</td></tr></tbody></table></section><section class="print-section"><h2 id="바로크-악기" tabindex="-1"><a class="header-anchor" href="#바로크-악기"><span>바로크 악기</span></a></h2><p>바로크 시대에는 현대 악기와 다른 형태의 악기들이 사용됐다.</p><table><thead><tr><th>악기</th><th>특징</th></tr></thead><tbody><tr><td><strong>하프시코드 (Harpsichord)</strong></td><td>건반 악기. 현을 뜯어 소리냄 (피아노와 달리 셈여림 조절 불가)</td></tr><tr><td><strong>바로크 바이올린</strong></td><td>현대 바이올린보다 넥 각도가 작고, 거트 현 사용</td></tr><tr><td><strong>비올 (Viol, Viola da Gamba)</strong></td><td>6현 찰현 악기. 첼로의 전신이나 연주법이 다름</td></tr><tr><td><strong>리코더 (Recorder)</strong></td><td>횡적 플루트 이전에 주류였던 종적 관악기</td></tr><tr><td><strong>류트 (Lute)</strong></td><td>통주저음의 화음 악기로 사용</td></tr><tr><td><strong>트럼펫·호른</strong></td><td>밸브 없는 자연 트럼펫(natural trumpet). 특정 배음 계열만 연주 가능</td></tr></tbody></table></section><section class="print-section"><h2 id="역사적-연주법-hip" tabindex="-1"><a class="header-anchor" href="#역사적-연주법-hip"><span>역사적 연주법 (HIP)</span></a></h2><p>20세기 후반부터 니콜라우스 아르농쿠르, 구스타프 레온하르트, 존 엘리엇 가디너 등 지휘자들이 이끄는 <strong>역사적 연주법(Historically Informed Performance)</strong> 운동이 확산되었다.</p><p>핵심 원칙:</p><ul><li>당대 악기(또는 복원 악기) 사용</li><li>당시 연주 관행(장식음 처리, 아티큘레이션, 템포 루바토 등) 복원</li><li>소규모 앙상블 편성 (낭만주의 시대의 대편성 오케스트라로 바흐를 연주하는 것에 대한 반성)</li></ul><p>현재 바로크 음악은 전통적인 현대 편성 연주와 HIP 연주 두 갈래가 공존하며, 각각의 해석이 미덕을 가진다.</p></section><section class="print-section"><h2 id="추천-입문-음악" tabindex="-1"><a class="header-anchor" href="#추천-입문-음악"><span>추천 입문 음악</span></a></h2><table><thead><tr><th>곡</th><th>작곡가</th><th>특징</th></tr></thead><tbody><tr><td>사계 (봄)</td><td>비발디</td><td>가장 친숙한 바로크 선율</td></tr><tr><td>브란덴부르크 협주곡 3번</td><td>바흐</td><td>현악 합주의 활력</td></tr><tr><td>메시아 (할렐루야)</td><td>헨델</td><td>압도적인 합창</td></tr><tr><td>토카타와 푸가 d단조</td><td>바흐</td><td>오르간의 웅장함</td></tr><tr><td>디도의 탄식</td><td>퍼셀</td><td>간결하고 비통한 아름다움</td></tr><tr><td>골드베르크 변주곡</td><td>바흐</td><td>그레의 Glenn Gould 녹음이 특히 유명</td></tr></tbody></table></section>`,15)])}var f=s(l,[[`render`,d]]);export{c as _pageData,f as default};